// 1. Sealed Interface limits implementations strictly to these three records
public sealed interface Shape permits Circle, Rectangle, Square {}

// 2. Records: Immutable data carriers (no boilerplate needed)
public record Circle(double radius) implements Shape {}
public record Rectangle(double length, double width) implements Shape {}
public record Square(double side) implements Shape {}

public class ModernJavaDemo {

    // 3. Pattern Matching for Switch
    public static double calculateArea(Shape shape) {
        // No default case needed! The compiler knows the hierarchy is sealed
        // and all possible subtypes are covered.
        return switch (shape) {
            case Circle c -> Math.PI * c.radius() * c.radius();
            case Rectangle r -> r.length() * r.width();
            case Square s -> s.side() * s.side();
        };
    }

    public static void main(String[] args) {
        // 4. var keyword for local variable inference
        var myShape = new Circle(5.0);
        System.out.println("Area: " + calculateArea(myShape));

        // 5. Text Blocks for clean multi-line strings
        String json = """
            {
                "type": "Circle",
                "radius": 5.0
            }
            """;
        System.out.println(json);
    }
}

